import React from 'react';
import {
  Container,
  Grid,
  Card,
  CardContent,
  Typography,
  Box,
  Button,
  Chip,
} from '@mui/material';
import { motion } from 'framer-motion';
import OpenInNewIcon from '@mui/icons-material/OpenInNew';

const MotionCard = motion(Card);

const Publications = () => {
  const publications = [
    {
      title: 'Building Scalable Microservices with Node.js',
      journal: 'Medium',
      date: '2023',
      link: 'https://medium.com/@yourusername/article-1',
      description: 'A comprehensive guide to building and deploying microservices using Node.js and Docker.',
      tags: ['Microservices', 'Node.js', 'Docker'],
    },
    {
      title: 'Machine Learning in Production: Best Practices',
      journal: 'Towards Data Science',
      date: '2023',
      link: 'https://towardsdatascience.com/@yourusername/article-2',
      description: 'Essential practices for deploying and maintaining machine learning models in production environments.',
      tags: ['Machine Learning', 'MLOps', 'Python'],
    },
    // Add more publications as needed
  ];

  return (
    <Container maxWidth="lg" sx={{ py: 8 }}>
      <Typography variant="h2" component="h1" gutterBottom align="center">
        Publications
      </Typography>
      <Typography
        variant="h5"
        color="text.secondary"
        paragraph
        align="center"
        sx={{ mb: 6 }}
      >
        Articles and technical publications
      </Typography>

      <Grid container spacing={4}>
        {publications.map((pub, index) => (
          <Grid item xs={12} key={index}>
            <MotionCard
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5, delay: index * 0.1 }}
              sx={{
                transition: 'transform 0.2s',
                '&:hover': {
                  transform: 'translateY(-8px)',
                },
              }}
            >
              <CardContent>
                <Box
                  sx={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'flex-start',
                    mb: 2,
                  }}
                >
                  <Box>
                    <Typography variant="h5" component="h2" gutterBottom>
                      {pub.title}
                    </Typography>
                    <Typography
                      variant="subtitle1"
                      color="text.secondary"
                      gutterBottom
                    >
                      {pub.journal} • {pub.date}
                    </Typography>
                  </Box>
                  <Button
                    variant="outlined"
                    endIcon={<OpenInNewIcon />}
                    href={pub.link}
                    target="_blank"
                  >
                    Read Article
                  </Button>
                </Box>

                <Typography
                  variant="body1"
                  color="text.secondary"
                  paragraph
                >
                  {pub.description}
                </Typography>

                <Box sx={{ mt: 2 }}>
                  {pub.tags.map((tag) => (
                    <Chip
                      key={tag}
                      label={tag}
                      size="small"
                      sx={{ mr: 1, mb: 1 }}
                    />
                  ))}
                </Box>
              </CardContent>
            </MotionCard>
          </Grid>
        ))}
      </Grid>
    </Container>
  );
};

export default Publications;
